public class MergeSort {

    public static void sort(int[] arr) {
        if (arr.length <= 1) return;
        mergeSort(arr, 0, arr.length - 1);
    }

    private static void mergeSort(int[] arr, int left, int right) {
        if (left >= right) return;           // base case: 0 or 1 element

        int mid = left + (right - left) / 2; // avoids overflow
        mergeSort(arr, left, mid);           // sort left half
        mergeSort(arr, mid + 1, right);      // sort right half
        merge(arr, left, mid, right);        // merge both halves
    }

    private static void merge(int[] arr, int left, int mid, int right) {
        // Copy both halves into a temp array
        int[] temp = new int[right - left + 1];
        int i = left, j = mid + 1, k = 0;

        while (i <= mid && j <= right) {
            // Stable: pick left element when equal (maintains original order)
            if (arr[i] <= arr[j]) temp[k++] = arr[i++];
            else                  temp[k++] = arr[j++];
        }

        // Copy remaining elements from either half
        while (i <= mid)   temp[k++] = arr[i++];
        while (j <= right) temp[k++] = arr[j++];

        // Write back into original array
        System.arraycopy(temp, 0, arr, left, temp.length);
    }

    public static void main(String[] args) {
        int[] arr = {38, 27, 43, 3, 9, 82, 10};
        sort(arr);
        System.out.println(Arrays.toString(arr)); // [3, 9, 10, 27, 38, 43, 82]
    }
}

public class QuickSort {

    public static void sort(int[] arr) {
        quickSort(arr, 0, arr.length - 1);
    }

    private static void quickSort(int[] arr, int low, int high) {
        if (low >= high) return;

        int pivotIdx = partition(arr, low, high);
        quickSort(arr, low, pivotIdx - 1);
        quickSort(arr, pivotIdx + 1, high);
    }

    // Lomuto partition scheme — pivot = arr[high]
    private static int partition(int[] arr, int low, int high) {
        int pivot = arr[high];
        int i = low - 1; // boundary of smaller elements

        for (int j = low; j < high; j++) {
            if (arr[j] <= pivot) {
                i++;
                swap(arr, i, j);
            }
        }
        swap(arr, i + 1, high); // place pivot in final position
        return i + 1;
    }

    // Randomized quick sort — avoids O(n²) on sorted input
    private static void randomizedSort(int[] arr, int low, int high) {
        if (low >= high) return;
        int r = low + (int)(Math.random() * (high - low + 1));
        swap(arr, r, high); // random pivot
        int pivotIdx = partition(arr, low, high);
        randomizedSort(arr, low, pivotIdx - 1);
        randomizedSort(arr, pivotIdx + 1, high);
    }

    private static void swap(int[] arr, int i, int j) {
        int tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp;
    }

    public static void main(String[] args) {
        int[] arr = {10, 7, 8, 9, 1, 5};
        sort(arr);
        System.out.println(Arrays.toString(arr)); // [1, 5, 7, 8, 9, 10]
    }
}

public class BubbleSort {

    // Basic bubble sort — O(n²) always
    public static void sort(int[] arr) {
        int n = arr.length;
        for (int pass = 0; pass < n - 1; pass++) {
            for (int i = 0; i < n - 1 - pass; i++) {
                if (arr[i] > arr[i + 1]) {
                    // swap
                    int temp = arr[i];
                    arr[i]   = arr[i + 1];
                    arr[i + 1] = temp;
                }
            }
        }
    }

    // Optimised — exits early if already sorted
    public static void sortOptimised(int[] arr) {
        int n = arr.length;
        for (int pass = 0; pass < n - 1; pass++) {
            boolean swapped = false;
            for (int i = 0; i < n - 1 - pass; i++) {
                if (arr[i] > arr[i + 1]) {
                    int temp   = arr[i];
                    arr[i]     = arr[i + 1];
                    arr[i + 1] = temp;
                    swapped = true;
                }
            }
            if (!swapped) break; // already sorted — O(n) best case
        }
    }

    public static void main(String[] args) {
        int[] arr = {64, 34, 25, 12, 22, 11, 90};
        sortOptimised(arr);
        System.out.println(Arrays.toString(arr)); // [11, 12, 22, 25, 34, 64, 90]
    }
}
